import { useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { FiMenu, FiX, FiSearch, FiExternalLink } from 'react-icons/fi';

const Header = () => {
  const [isOpen, setIsOpen] = useState(false);

  return (
    <header className="bg-white/90 backdrop-blur-md shadow-sm fixed w-full z-50">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="flex justify-between items-center h-16">
          {/* Logo with animated radar icon */}
          <div className="flex-shrink-0 flex items-center">
            <div className="relative h-8 w-8 mr-2">
              <div className="absolute inset-0 rounded-full border-2 border-purple-600 flex items-center justify-center">
                <div className="h-2 w-2 rounded-full bg-purple-500 animate-ping" />
              </div>
              <div className="absolute inset-1 rounded-full bg-gradient-to-br from-purple-500 to-blue-400" />
            </div>
            <span className="text-xl font-bold bg-gradient-to-r from-purple-600 to-blue-500 bg-clip-text text-transparent">
              DeepFake Detector
            </span>
          </div>

          {/* Desktop Navigation */}
          <nav className="hidden md:flex space-x-6 items-center">
            <motion.a
              href="#documentation"
              className="text-gray-700 hover:text-purple-600 font-medium text-sm flex items-center"
              whileHover={{ y: -2 }}
            >
              Documentation <FiExternalLink className="ml-1" />
            </motion.a>
            
            <motion.a
              href="#contact"
              className="text-gray-700 hover:text-purple-600 font-medium text-sm"
              whileHover={{ y: -2 }}
            >
              Contact
            </motion.a>

            <motion.button
              className="bg-gradient-to-r from-purple-600 to-blue-500 text-white px-4 py-2 rounded-md text-sm font-medium shadow-md flex items-center"
              whileHover={{ scale: 1.05 }}
              whileTap={{ scale: 0.95 }}
            >
              Try Demo <FiExternalLink className="ml-1" />
            </motion.button>
          </nav>

          {/* Mobile menu button */}
          <div className="md:hidden">
            <button
              onClick={() => setIsOpen(!isOpen)}
              className="p-2 rounded-md text-gray-700 hover:text-purple-600 focus:outline-none"
            >
              {isOpen ? <FiX className="h-6 w-6" /> : <FiMenu className="h-6 w-6" />}
            </button>
          </div>
        </div>
      </div>

      {/* Mobile menu */}
      <AnimatePresence>
        {isOpen && (
          <motion.div
            initial={{ opacity: 0, height: 0 }}
            animate={{ opacity: 1, height: 'auto' }}
            exit={{ opacity: 0, height: 0 }}
            transition={{ duration: 0.2 }}
            className="md:hidden overflow-hidden bg-white"
          >
            <div className="px-2 pt-2 pb-4 space-y-2">
              <a
                href="#documentation"
                className="flex items-center px-3 py-2 rounded-md text-base font-medium text-gray-700 hover:bg-gray-50"
                onClick={() => setIsOpen(false)}
              >
                Documentation <FiExternalLink className="ml-2" />
              </a>
              <a
                href="#contact"
                className="block px-3 py-2 rounded-md text-base font-medium text-gray-700 hover:bg-gray-50"
                onClick={() => setIsOpen(false)}
              >
                Contact
              </a>
              <button
                className="w-full flex items-center justify-center mt-2 bg-gradient-to-r from-purple-600 to-blue-500 text-white px-4 py-2 rounded-md text-base font-medium shadow-md"
                onClick={() => setIsOpen(false)}
              >
                Try Demo <FiExternalLink className="ml-2" />
              </button>
            </div>
          </motion.div>
        )}
      </AnimatePresence>
    </header>
  );
};

export default Header;
